css:
.loader {
  color: var(--loader-color, #e11d48);
  display: inline-grid;
  animation: l10-0 2s infinite steps(1);
}
.loader:before,
.loader:after {
  content: "";
  height: 27px;
  aspect-ratio: 5;
  --c: currentColor 90deg,#0000 0;
  background:
   conic-gradient(from 135deg at top   ,var(--c)),
   conic-gradient(from -45deg at bottom,var(--c)) 12.5% 100%;
  background-size: 20% 50%;
  background-repeat: repeat-x;
  clip-path: inset(0 100% 0 0);
  animation: l10-1 1s infinite linear alternate;
}
.loader:after {
  scale: -1 1;
}
@keyframes l10-0{
  50% {scale: -1 1}
}
@keyframes l10-1{
  to {clip-path: inset(0)}
}
